import{_ as l,o as e,c as t,ag as a}from"./chunks/framework.DXGyWiRo.js";const n="/images/uebung043.jpg",h=JSON.parse('{"title":"Übung Lektion 26","description":"","frontmatter":{},"headers":[],"relativePath":"lektionen/uebung26.md","filePath":"lektionen/uebung26.md"}'),r={name:"lektionen/uebung26.md"};function o(s,i,u,p,m,d){return e(),t("div",null,[...i[0]||(i[0]=[a('<div class="info custom-block github-alert"><p class="custom-block-title">Zitierweise &amp; Rechte</p><p>Dieses Kapitel ist Teil des Sanskritkurses. Details zum Copyright und zur Zitierweise der Ursprungsfassung siehe: <a href="/impressum">Impressum &amp; Copyright</a></p></div><h1 id="ubung-lektion-26" tabindex="-1">Übung Lektion 26 <a class="header-anchor" href="#ubung-lektion-26" aria-label="Permalink to &quot;Übung Lektion 26&quot;">​</a></h1><p>Bilden Sie die in Zahl, Person und Genus verbi (Parasmaipada, Ātmanepada) entsprechenden Futurformen:</p><p>A) ohne Bindevokal -i-:</p><ol><li>अत्ति अत्स्यति</li><li>प्राप्नुवन्ति प्राप्स्यन्ति</li><li>सम्यन्ति समेष्यन्ति</li><li>विजयन्ते विजेष्यन्ते</li><li>दहन् धक्ष्यन्</li><li>आदिशन्ति आदेक्ष्यन्ति</li><li>दोग्धि धोक्ष्यति</li><li>पश्यति (Futur von दृश् bilden) द्रक्ष्यति</li><li>उपानयन्ति उपानेष्यन्ति</li><li>पचति पक्ष्यति</li><li>उपपद्यन्ते उपपत्स्यन्ते</li><li>पिबति पास्यति</li><li>पृच्छति प्रक्ष्यति</li><li>बुध्यन्ते भित्स्यन्ते</li><li>मन्यते मंस्यते</li><li>मुञ्चति मोक्ष्यति</li><li>यजते यक्ष्यते</li><li>युध्यन्ते योत्स्यन्ते</li><li>भजति भक्ष्यति</li><li>कृषति कर्क्ष्यति । क्रक्ष्यति</li><li>क्रुध्यन्ति क्रोत्स्यन्ति</li><li>दुष्यति दोक्ष्यन्ति</li><li>द्वेष्टि द्वेक्ष्यति</li><li>पान्ति पास्यन्ति</li><li>सीदति सत्स्यति</li><li>लभते लप्स्यते</li><li>वक्ति वक्ष्यति</li><li>प्रविशन्ति प्रवेक्ष्यन्ति</li><li>शक्नोति शक्ष्यति</li><li>शृणोति श्रोष्यति</li><li>सिञ्चति सेक्ष्यति</li><li>सुन्वन्ति सोष्यन्ति</li><li>सृजति स्रक्ष्यति</li><li>स्तौति स्तोष्यति</li><li>तिष्ठति स्थास्यति</li></ol><p>B) Mit Bindevokal -i-:</p><ol><li>अस्यति असिष्यति</li><li>आसते आसिष्यन्ते</li><li>इच्छति एषिष्यति</li><li>संस्करोति संस्करिष्यति</li><li>खादति खादिष्यति</li><li>लुभ्यति लोभिष्यते</li><li>तनुते तनिष्यते</li><li>उपागच्छन्ति अपागमिष्यन्ति</li><li>चरति चरिष्यति</li><li>जायन्ते जनिष्यन्ते</li><li>नृत्यति नर्तिष्यति</li><li>सहते सहिष्यते</li><li>पतन्ति पतिष्यन्ति</li><li>रोदिति रोदिष्यति</li><li>प्रभवति प्रभविष्यति</li><li>म्रियन्ते (im Futur Parasmaipada) मरिष्यन्ति</li><li>जीवन्ति जीविष्यन्ति</li><li>रक्षति रक्षिष्यति</li><li>वदति वदिष्यति</li><li>स्मरति स्मरिष्यति</li><li>घ्नन्ति हनिष्यन्ति</li><li>अर्हन्ति अर्हिष्यन्ति</li><li>कुप्यन्ति कोपिष्यन्ति</li></ol><p>C) Futur optionell mit und ohne -i-:</p><ol><li>मुह्यन्ति मोहिष्यन्ति । मोक्ष्यन्ति</li><li>वर्तते वर्तिष्यते । वएर्त्स्यते</li><li>अश्नुवते (im Futur Parasmaipada) अशिष्यन्ति । अक्ष्यन्ति</li></ol><p><img src="'+n+'" alt=""><br> Abb.: अविपालो ऽविं रक्षति (अवि m. Schaf)<br> Uttarakhand = उत्तराखण्ड<br> [Bildquelle: aRfi!. -- <a href="http://www.flickr.com/photos/zutshy/2639124622/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/zutshy/2639124622/</a>. -- Zugriff am 2008-12-29. -- <a href="http://creativecommons.org/licenses/by-nc-nd/2.0/deed.de" target="_blank" rel="noreferrer"></a>Creative Commons Lizenz (Namensnennung, keine kommerzielle Nutzung, keine Bearbeitung)]</p>',10)])])}const g=l(r,[["render",o]]);export{h as __pageData,g as default};
